// 1. Get Data
const allItems = $input.all().map(i => i.json);

// 2. Get Memory & Constraints
let userKeyword = "macbook";
let userSpecs = "";
let minPrice = 0;
let maxPrice = 10000000;
let offset = 0;

try {
    const formData = $('Parse Form').first().json;
    if (formData.error) return { json: { message: formData.error } }; // Handle "No memory" error

    userKeyword = formData.keyword.toLowerCase();
    userSpecs = (formData.specs || "").toLowerCase();
    minPrice = formData.minPrice || 0;
    maxPrice = formData.maxPrice || 10000000;
    offset = formData.offset || 0; // How many to skip
} catch (e) { console.log("Using defaults"); }

const requiredWords = userKeyword.split(' ').filter(w => w.length > 0);
const specWords = userSpecs.split(',').map(s => s.trim()).filter(s => s.length > 0);

// 3. SMART FILTER
const cleanList = allItems.filter(item => {
  const title = (item.marketplace_listing_title || item.title || "").toLowerCase();
  const mainMatch = requiredWords.every(word => title.includes(word));

  let specsMatch = true;
  if (specWords.length > 0) {
      specsMatch = specWords.some(opt => title.includes(opt));
  }

  let priceRaw = "0";
  if (item.listing_price && item.listing_price.amount) priceRaw = item.listing_price.amount; 
  else if (item.price) priceRaw = item.price;

  let priceVal = parseFloat(priceRaw.toString().replace(/[^0-9.]/g, ""));
  if (isNaN(priceVal)) priceVal = 0;

  const priceMatch = (priceVal >= minPrice && priceVal <= maxPrice);

  return mainMatch && specsMatch && priceMatch;
});

// 4. SLICE THE LIST (Pagination)
// If offset is 8, we start showing from item 8
const newItems = cleanList.slice(offset, offset + 8);

// 5. Create Message
let message = `🚨 *Results for: ${userKeyword}* (Page ${offset/8 + 1}) 🚨\n`;
if (userSpecs) message += `_(Filtered for: ${userSpecs})_\n`;

newItems.forEach(item => {
   const title = (item.marketplace_listing_title || item.title || "No Title").replace(/\*/g, ""); 
   let displayPrice = item.listing_price ? item.listing_price.formatted_amount : (item.price || "N/A");
   let url = item.listingUrl || `https://www.facebook.com/marketplace/item/${item.id}`;

   message += `• *${title}* - ${displayPrice}\n${url}\n\n`;
});

if (newItems.length === 0) {
  message = `No more items found for "${userKeyword}".\n(Scanned ${allItems.length} items total).`;
}

return { json: { message } };

// 1. Access Memory (The Fix: use 'this.')
let staticData;
try {
    staticData = this.getWorkflowStaticData('global');
} catch (e) {
    // Fallback for testing mode if memory fails
    staticData = {}; 
}

const text = $input.item.json.message.text || "";

// Defaults
let keyword = "";
let specs = "";
let minPrice = 0;
let maxPrice = 10000000;
let offset = 0;

// 2. CHECK: Is this a "/more" command?
if (text.trim().toLowerCase() === "/more") {
    const last = staticData.lastSearch;

    if (last && last.keyword) {
        // LOAD previous settings
        keyword = last.keyword;
        specs = last.specs;
        minPrice = last.minPrice;
        maxPrice = last.maxPrice;
        // INCREASE Offset (Skip previous items)
        offset = (staticData.lastOffset || 0) + 8;
    } else {
        // No memory found
        return { json: { error: "I forgot your last search! Please start a new one." } };
    }
} 
else {
    // 3. NEW SEARCH (Parse the Form)
    offset = 0; // Reset page to 0

    const itemMatch = text.match(/item\s*[:=]\s*(.+)/i);
    if (itemMatch) keyword = itemMatch[1].trim();
    else keyword = text.split('\n')[0].trim();

    const specsMatch = text.match(/(?:specs|keywords|details)\s*[:=]\s*(.+)/i);
    if (specsMatch) specs = specsMatch[1].trim();

    const minMatch = text.match(/min(?:imum)?\s*(?:price)?\s*[:=]\s*([\d,]+)/i);
    if (minMatch) minPrice = parseInt(minMatch[1].replace(/,/g, ''));

    const maxMatch = text.match(/max(?:imum)?\s*(?:price)?\s*[:=]\s*([\d,]+)/i);
    if (maxMatch) maxPrice = parseInt(maxMatch[1].replace(/,/g, ''));

    // 4. SAVE to Memory
    staticData.lastSearch = { keyword, specs, minPrice, maxPrice };
}

// Update the offset in memory for next time
staticData.lastOffset = offset;

return {
  json: {
    keyword,
    specs,
    minPrice,
    maxPrice,
    offset // Pass this to Apify
  }
};
